@using Microsoft.AspNetCore.Components.Forms

<div class="file-drop-zone @(_isDragOver ? "drag-over" : "")"
     @ondragenter="HandleDragEnter"
     @ondragover="HandleDragOver"
     @ondragleave="HandleDragLeave"
     @ondrop="HandleDrop">
    <InputFile @ref="_inputFile" OnChange="HandleFileSelected" multiple hidden id="@_inputId" />
    <p class="file-drop-zone-prompt">Drag &amp; drop files here or <label for="@_inputId" class="file-drop-zone-browse">browse</label></p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-drop-zone-list">
        @foreach (var entry in _files)
        {
            <li class="file-drop-zone-item @(entry.Error is not null ? "file-error" : "")">
                <div class="file-info">
                    <span class="file-name">@entry.Info.Name</span>
                    <span class="file-size">@FormatSize(entry.Info.Size)</span>
                    <span class="file-type">@(string.IsNullOrEmpty(entry.Info.Type) ? "unknown" : entry.Info.Type)</span>
                    @if (entry.Error is not null)
                    {
                        <span class="file-error-message">@entry.Error</span>
                    }
                </div>
                <button class="file-remove-btn" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSizeBytes = 10 * 1024 * 1024; // 10 MB

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private bool _isDragOver;
    private readonly List<FileEntry> _files = new();
    private InputFile? _inputFile;
    private readonly string _inputId = $"file-input-{Guid.NewGuid():N}";

    private void HandleDragEnter() => _isDragOver = true;
    private void HandleDragOver() => _isDragOver = true;
    private void HandleDragLeave() => _isDragOver = false;

    private async Task HandleDrop(DragEventArgs e)
    {
        _isDragOver = false;
        // File data comes through InputFile's OnChange; drop alone doesn't provide file content in Blazor.
        // The InputFile is used as the underlying mechanism.
    }

    private async Task HandleFileSelected(InputFileChangeEventArgs e)
    {
        foreach (var file in e.GetMultipleFiles(100))
        {
            var info = new FileInfo(file.Name, file.Size, file.ContentType);
            string? error = file.Size > MaxFileSizeBytes
                ? $"File exceeds the 10 MB limit ({FormatSize(file.Size)})"
                : null;
            _files.Add(new FileEntry(info, error));
        }

        await NotifyParent();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files
            .Where(f => f.Error is null)
            .Select(f => f.Info)
            .ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    private sealed record FileEntry(FileInfo Info, string? Error);
}

.file-drop-zone {
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 2rem;
    text-align: center;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: pointer;
}

.file-drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: rgba(13, 110, 253, 0.05);
}

.file-drop-zone-prompt {
    margin: 0;
    color: #6c757d;
}

.file-drop-zone-browse {
    color: #0d6efd;
    cursor: pointer;
    text-decoration: underline;
}

.file-drop-zone-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-drop-zone-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-drop-zone-item.file-error {
    border-color: #dc3545;
    background-color: rgba(220, 53, 69, 0.05);
}

.file-info {
    display: flex;
    flex-wrap: wrap;
    gap: 0.75rem;
    align-items: center;
}

.file-name {
    font-weight: 500;
}

.file-size,
.file-type {
    color: #6c757d;
    font-size: 0.875rem;
}

.file-error-message {
    color: #dc3545;
    font-size: 0.875rem;
    font-weight: 500;
}

.file-remove-btn {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.25rem 0.5rem;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
}

.file-remove-btn:hover {
    background-color: #dc3545;
    color: #fff;
}

